final:
module RefModule (
    input clk,
    input rst,
    input en,
    input data_in,
    output reg [7:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q <= 8'b00000000;
        else if (en)
            q <= {data_in, q[7:1]};
    end

endmodule
